export async function embedInBatches(
  { texts, run, batchSize, prefix }: { texts: readonly string[]; run: ExtractionPipeline; batchSize: number; prefix: string },
): Promise<readonly Float32Array[]> {
  if (batchSize <= 0) {
    throw new Error(`batchSize must be positive, got ${batchSize}`)
  }
  const vectors: Float32Array[] = []
  for (let i = 0; i < texts.length; i += batchSize) {
    const batch = texts.slice(i, i + batchSize).map((text) => `${prefix}${text.slice(0, MAX_EMBED_CHARS)}`)
    const result = await run(batch, { pooling: 'mean', normalize: true })
    vectors.push(...splitBatchVectors({ data: result.data, count: batch.length }))
  }
  return vectors
}
```

